use std::path::{Path, PathBuf};
use std::process::Command;

fn convert_file(filename: &str, output_format: &str) -> Result<PathBuf, String> {
    let filename = Path::new(filename);
    let output_dir = filename.parent().unwrap_or(Path::new("."));
    let mut output_filename = filename.file_name().unwrap().to_string_lossy().into_owned();
    output_filename.push_str(".");
    output_filename.push_str(output_format);

    let command = Command::new("convert")
        .arg("-format")
        .arg(output_format)
        .arg(filename)
        .output()?;

    if command.status.success() {
        let output_path = PathBuf::from(output_dir).join(output_filename);
        return Ok(output_path);
    }

    Err(format!("Failed to convert file: {}", filename))
}

fn convert_jpeg_to_png(input_file: &str) -> Result<PathBuf, String> {
    convert_file(input_file, "png")
}

fn convert_pptx_to_pdf(input_file: &str) -> Result<PathBuf, String> {
    // Use libreoffice --headless to convert pptx
    Command::new("libreoffice")
        .arg("--headless")
        .arg("-convert-to")
        .arg("pdf")
        .arg(input_file)
        .output()?;

    let output_dir = Path::new(input_file).parent().unwrap_or(Path::new("."));
    let mut output_filename = input_file.file_name().unwrap().to_string_lossy().into_owned();
    output_filename.push_str(".pdf");

    let output_path = PathBuf::from(output_dir).join(output_filename);
    Ok(output_path)
}